import React, { useState, useEffect } from 'react';
import { Keyboard, Package, Sparkles, Star, DollarSign, ShoppingCart } from 'lucide-react';

const KEYBOARDS = [
  { id: 1, name: 'Logitech K120', rarity: 'Common', description: 'Standard office keyboard. Gets the job done.', color: '#9ca3af', price: 5, image: 'data:image/jpeg;base64,' },
  { id: 2, name: 'Razer Cynosa Lite', rarity: 'Common', description: 'Entry-level gaming keyboard with RGB.', color: '#9ca3af', price: 8, image: 'data:image/jpeg;base64,' },
  { id: 3, name: 'HyperX Alloy Core', rarity: 'Uncommon', description: 'Reliable membrane keyboard with quiet keys.', color: '#22c55e', price: 15, image: 'data:image/jpeg;base64,' },
  { id: 4, name: 'Redragon K552', rarity: 'Uncommon', description: 'Compact mechanical with blue switches.', color: '#22c55e', price: 18, image: 'data:image/jpeg;base64,' },
  { id: 5, name: 'SteelSeries Apex 3', rarity: 'Rare', description: 'Premium membrane with whisper-quiet keys.', color: '#3b82f6', price: 35, image: 'data:image/jpeg;base64,' },
  { id: 6, name: 'Logitech G213', rarity: 'Rare', description: 'RGB gaming keyboard with Mech-Dome keys.', color: '#3b82f6', price: 40, image: 'data:image/jpeg;base64,' },
  { id: 7, name: 'Corsair K100 RGB', rarity: 'Epic', description: 'Flagship keyboard with OPX optical switches.', color: '#a855f7', price: 120, image: 'data:image/jpeg;base64,' },
  { id: 8, name: 'Razer BlackWidow 75%', rarity: 'Epic', description: 'Premium compact with green tactile switches.', color: '#a855f7', price: 110, image: 'data:image/jpeg;base64,' },
  { id: 9, name: 'Gold Rush Razer Huntsman', rarity: 'Legendary', description: 'Ultra-rare Dragon Lore edition. The holy grail.', color: '#eab308', price: 500, image: 'data:image/jpeg;base64,' },
];

const CASES = {
  Starter: {
    name: 'Starter Case',
    price: 10,
    icon: '📦',
    dropRates: { Common: 60, Uncommon: 30, Rare: 9, Epic: 0.9, Legendary: 0.1 }
  },
  Premium: {
    name: 'Premium Case',
    price: 25,
    icon: '🎁',
    dropRates: { Common: 40, Uncommon: 35, Rare: 20, Epic: 4.5, Legendary: 0.5 }
  },
  Vintage: {
    name: 'Vintage Case',
    price: 50,
    icon: '💎',
    dropRates: { Common: 30, Uncommon: 30, Rare: 30, Epic: 9, Legendary: 1 }
  }
};

export default function KeyboardCaseOpener() {
  const [selectedCase, setSelectedCase] = useState('Starter');
  const [isOpening, setIsOpening] = useState(false);
  const [rollingItems, setRollingItems] = useState([]);
  const [result, setResult] = useState(null);
  const [inventory, setInventory] = useState([]);
  const [showInventory, setShowInventory] = useState(false);
  const [money, setMoney] = useState(50);

  const getRandomKeyboard = (caseType) => {
    const rates = CASES[caseType].dropRates;
    const random = Math.random() * 100;
    
    let cumulative = 0;
    for (const [rarity, rate] of Object.entries(rates)) {
      cumulative += rate;
      if (random <= cumulative) {
        const available = KEYBOARDS.filter(k => k.rarity === rarity);
        return available[Math.floor(Math.random() * available.length)];
      }
    }
    return KEYBOARDS[0];
  };

  const openCase = () => {
    const casePrice = CASES[selectedCase].price;
    if (money < casePrice) {
      alert('Not enough money! You need $' + casePrice + ' but only have $' + money);
      return;
    }

    setMoney(money - casePrice);
    setIsOpening(true);
    setResult(null);
    
    const finalItem = getRandomKeyboard(selectedCase);
    
    const items = [];
    for (let i = 0; i < 30; i++) {
      items.push(getRandomKeyboard(selectedCase));
    }
    
    items[24] = finalItem;
    setRollingItems(items);
    
    setTimeout(() => {
      setIsOpening(false);
      setResult(finalItem);
      setInventory([...inventory, { ...finalItem, id: Date.now() }]);
    }, 3500);
  };

  const sellKeyboard = (idx) => {
    const item = inventory[idx];
    setMoney(money + item.price);
    setInventory(inventory.filter((_, i) => i !== idx));
  };

  const sellAll = () => {
    const total = inventory.reduce((sum, item) => sum + item.price, 0);
    setMoney(money + total);
    setInventory([]);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 text-white p-8">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-8">
          <h1 className="text-5xl font-bold mb-4 bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text text-transparent">
            KeyDrop Case Opening
          </h1>
          <div className="flex items-center justify-center gap-2 text-3xl font-bold text-green-400">
            <DollarSign size={32} />
            <span>${money}</span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          {Object.entries(CASES).map(([key, caseInfo]) => (
            <button
              key={key}
              onClick={() => setSelectedCase(key)}
              className={'p-6 rounded-xl transition-all ' + (selectedCase === key ? 'bg-purple-600 shadow-lg shadow-purple-500/50 scale-105' : 'bg-slate-800 hover:bg-slate-700')}
            >
              <div className="text-6xl mb-4">{caseInfo.icon}</div>
              <h3 className="text-xl font-bold mb-2">{caseInfo.name}</h3>
              <p className="text-2xl font-bold text-green-300 mb-4">${caseInfo.price}</p>
              <div className="text-sm text-gray-400 space-y-1">
                {Object.entries(caseInfo.dropRates).map(([rarity, rate]) => (
                  <div key={rarity} className="flex justify-between">
                    <span>{rarity}:</span>
                    <span className="font-mono">{rate}%</span>
                  </div>
                ))}
              </div>
            </button>
          ))}
        </div>

        <div className="mb-12">
          {isOpening && (
            <div className="bg-slate-800 rounded-xl p-8 overflow-hidden relative">
              <div className="relative h-48 overflow-hidden">
                <div className="absolute left-1/2 top-0 bottom-0 w-1 bg-yellow-400 z-10 -ml-0.5"></div>
                <div 
                  className="flex gap-4"
                  style={{
                    animation: 'scroll 3.5s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards',
                    paddingLeft: 'calc(50% - 80px)',
                  }}
                >
                  {rollingItems.map((item, idx) => (
                    <div
                      key={idx}
                      className="flex-shrink-0 w-40 h-48 rounded-lg p-2 flex flex-col items-center justify-center"
                      style={{ backgroundColor: item.color + '20', borderColor: item.color, borderWidth: '2px' }}
                    >
                      <img src={item.image} alt={item.name} className="w-32 h-24 object-contain mb-2" />
                      <p className="text-xs text-center font-semibold">{item.name}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {result && !isOpening && (
            <div className="bg-slate-800 rounded-xl p-12 text-center animate-bounce-in">
              <div 
                className="inline-block p-8 rounded-xl mb-6"
                style={{ backgroundColor: result.color + '20', borderColor: result.color, borderWidth: '3px' }}
              >
                <img src={result.image} alt={result.name} className="w-64 h-48 object-contain mx-auto" />
              </div>
              <h2 className="text-4xl font-bold mb-4" style={{ color: result.color }}>
                {result.rarity}!
              </h2>
              <h3 className="text-3xl font-bold mb-4">{result.name}</h3>
              <p className="text-gray-300 text-lg mb-4">{result.description}</p>
              <p className="text-green-400 text-2xl font-bold">Worth: ${result.price}</p>
            </div>
          )}
        </div>

        <div className="flex gap-4 justify-center mb-8">
          <button
            onClick={openCase}
            disabled={isOpening || money < CASES[selectedCase].price}
            className="bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 disabled:opacity-50 disabled:cursor-not-allowed px-12 py-4 rounded-xl font-bold text-xl transition-all shadow-lg hover:shadow-purple-500/50"
          >
            {isOpening ? 'Opening...' : 'Open $' + CASES[selectedCase].price}
          </button>
          <button
            onClick={() => setShowInventory(!showInventory)}
            className="bg-slate-700 hover:bg-slate-600 px-8 py-4 rounded-xl font-bold transition-all"
          >
            Inventory ({inventory.length})
          </button>
        </div>

        {showInventory && (
          <div className="bg-slate-800 rounded-xl p-8">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold">Your Collection</h2>
              {inventory.length > 0 && (
                <button
                  onClick={sellAll}
                  className="bg-green-600 hover:bg-green-700 px-6 py-2 rounded-lg font-bold transition-all"
                >
                  Sell All (${inventory.reduce((sum, item) => sum + item.price, 0)})
                </button>
              )}
            </div>
            {inventory.length === 0 ? (
              <p className="text-gray-400 text-center py-8">Open some cases to start your collection!</p>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {inventory.map((item, idx) => (
                  <div
                    key={idx}
                    className="rounded-lg p-4 flex flex-col items-center relative group"
                    style={{ backgroundColor: item.color + '20', borderColor: item.color, borderWidth: '2px' }}
                  >
                    <img src={item.image} alt={item.name} className="w-24 h-16 object-contain mb-2" />
                    <p className="text-xs text-center font-semibold">{item.name}</p>
                    <p className="text-xs text-gray-400">{item.rarity}</p>
                    <p className="text-sm text-green-400 font-bold">${item.price}</p>
                    <button
                      onClick={() => sellKeyboard(idx)}
                      className="mt-2 bg-green-600 hover:bg-green-700 px-4 py-1 rounded text-xs font-bold transition-all"
                    >
                      Sell
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        <style>{`
          @keyframes scroll {
            0% { transform: translateX(0); }
            100% { transform: translateX(calc(-176px * 24)); }
          }
          @keyframes bounce-in {
            0% { transform: scale(0); opacity: 0; }
            50% { transform: scale(1.1); }
            100% { transform: scale(1); opacity: 1; }
          }
        `}</style>
      </div>
    </div>
  );
}